4395,0.04064635,-0.03751033,0.05495612,-0.03371537,-0.00454660,0.05160873,-0.00171083,-0.00503004,-0.00629380,0.01784563,0.01015099,0.03471793,-0.02239449,-0.03101035,0.00043587,-0.02804989,-0.01379500,-0.08563416,0.02326062,-0.02237381,-0.01187332,0.02286331,-0.03699668,-0.09560471,-0.03439987,-0.06958435,-0.00164143,0.00101560,-0.06617103,-0.02947611,-0.02049670,0.00736942,0.06355232,0.04142226,0.00244999,-0.08237462,0.02998422,0.02673198,0.04360409,0.06108267,0.07260644,0.03727818]',E'Library-specific approach\n\n@Controller(''cats'')\nexport class CatsController {\n  @Post()\n  create(@Res() res: Response) {\n    res.status(HttpStatus.CREATED).send();\n  }\n\n  @Get()\n  findAll(@Res() res: Response) {\n     res.status(HttpStatus.OK).json([]);\n  }\n}\n@@switch\nimport { Controller, Get, Post, Bind, Res, Body, HttpStatus } from ''@nestjs/common'';\n\n@Controller(''cats'')\nexport class CatsController {\n  @Post()\n  @Bind(Res(), Body())\n  create(res, createCatDto) {\n    res.status(HttpStatus.CREATED).send();\n  }','{"source": "nestjs", "version": "11", "language": "typescript", "title": "Controllers", "section_title": "controllers", "url": "https://github.com/nestjs/docs.nestjs.com/blob/master/content/controllers.md", "topics": "nestjs,typescript,controllers", "categories": "web,typescript,rest,enterprise"}');
