627,0.23383929,0.00359155,-0.02632312,0.04181791,-0.04725721,-0.04140495,0.02690436,0.03812338,-0.00411287,-0.00468273,0.02228331,-0.01115103,-0.00863643,-0.01237680,-0.04108785,0.00005901,-0.00373119,0.03830922,-0.06377918,-0.00237311,-0.01318216,-0.01635268,0.04596623,-0.07977082,-0.08350219,-0.04703317,-0.06687578,0.01196442,0.00467717,-0.05694533,-0.07095895,-0.01665319,-0.03986718,0.03677379,0.04742817,0.03302894,-0.05365935,0.02973352,0.00275615,-0.01518373,0.10308713,0.07182013,0.04998734]',E'Feature modules\n\nNext, we''ll create the `CatsModule` to demonstrate how to group the controller and service.\n\n```typescript\n@@filename(cats/cats.module)\nimport { Module } from ''@nestjs/common'';\nimport { CatsController } from ''./cats.controller'';\nimport { CatsService } from ''./cats.service'';\n\n@Module({\n  controllers: [CatsController],\n  providers: [CatsService],\n})\nexport class CatsModule {}\n```\n\n> info **Hint** To create a module using the CLI, simply execute the `$ nest g module cats` command.','{"source": "nestjs", "version": "11", "language": "typescript", "title": "Modules", "section_title": "modules", "url": "https://github.com/nestjs/docs.nestjs.com/blob/master/content/modules.md", "topics": "nestjs,typescript,modules", "categories": "web,typescript,rest,enterprise"}');
