3154615,0.01005406,-0.01245892,-0.06232289,0.01411967,-0.01401841,0.03260672,-0.03297493,-0.03224254,0.04680654,0.00102593,0.03085938,-0.05620049,-0.03462894,0.01355568,0.01980528,0.04005545,-0.05558839,-0.00967700,-0.03379513,-0.02885909,0.01052849,-0.06994074,-0.05416672,-0.07815564,-0.04643011,0.03710294,0.00041728,-0.04229636,0.02533334,0.00173490,-0.05220037,0.02164205,0.06591322,0.01751664,-0.10164148,0.01525220,0.01984700,-0.01780685,0.04858937,0.12502345,-0.00576319]',E'Dependency injection\n\nA module class can **inject** providers as well (e.g., for configuration purposes):\n\n```typescript\n@@filename(cats.module)\nimport { Module } from ''@nestjs/common'';\nimport { CatsController } from ''./cats.controller'';\nimport { CatsService } from ''./cats.service'';\n\n@Module({\n  controllers: [CatsController],\n  providers: [CatsService],\n})\nexport class CatsModule {\n  constructor(private catsService: CatsService) {}\n}\n@@switch\nimport { Module, Dependencies } from ''@nestjs/common'';\nimport { CatsController } from ''./cats.controller'';\nimport { CatsService } from ''./cats.service'';\n\n@Module({\n  controllers: [CatsController],\n  providers: [CatsService],\n})\n@Dependencies(CatsService)\nexport class CatsModule {\n  constructor(catsService) {\n    this.catsService = catsService;\n  }\n}\n```\n\nHowever, module classes themselves cannot be injected as providers due to [circular dependency](/fundamentals/circular-dependency) .','{"source": "nestjs", "version": "11", "language": "typescript", "title": "Modules", "section_title": "modules", "url": "https://github.com/nestjs/docs.nestjs.com/blob/master/content/modules.md", "topics": "nestjs,typescript,modules", "categories": "web,typescript,rest,enterprise"}');
